def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 1.2:
            priorities[i] = float('inf')
            continue
        base_score = 0.0
        temp_ratio = ratio
        for j in range(7):
            weight = 1 / (j + 1)
            if temp_ratio < 0.05:
                base_score += weight * 0.5
                break
            increment = (np.log1p(temp_ratio) ** 2 + np.sqrt(temp_ratio + 0.05)) * weight
            base_score += increment
            temp_ratio *= 0.8
            if base_score > 7:
                break
        if base_score < 1:
            base_score *= 3
            for k in range(3):
                base_score += (0.05 / (k + 1)) * (1 - ratio) * (k + 2)
        elif base_score < 4:
            base_score *= 6
            if capacity < item * 1.1:
                base_score += 4
        else:
            if ratio > 0.9:
                base_score *= 15
            elif ratio > 0.7:
                base_score *= 10
            else:
                base_score *= 5
        if capacity < item * 0.85:
            base_score += 25
        if capacity > item * 2:
            base_score -= 1.5
        if base_score < 0:
            base_score = 0
        priorities[i] = base_score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return np.full_like(priorities, float('inf'))
    min_p = np.min(finite_priorities)
    max_p = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_p * 120
        else:
            if priorities[i] == min_p:
                priorities[i] = 0
            elif priorities[i] == max_p:
                priorities[i] *= 2
            else:
                norm = (priorities[i] - min_p) / (max_p - min_p)
                if norm < 0.3:
                    priorities[i] = norm * 15
                elif norm < 0.7:
                    priorities[i] = norm * 12 + 2
                else:
                    priorities[i] = norm * 20 - 5
    return priorities
